CREATE TABLE `investments` (
  `id` int NOT NULL AUTO_INCREMENT,
  `website_app_name` varchar(255) NOT NULL,
  `investment_type` enum('FD','Stock','ETF','Bond','Mutual Fund','Crypto','PPF','Saving Bank Balance') NOT NULL,
